        { query: refinedQuery, depth: depth + 1 }
      );

      if (!recursiveHandle.ok) {
        throw new Error(
          `[researchAgent] Recursive researchAgent failed: ${recursiveHandle.error}`
        );
      }

      return recursiveHandle.output;
    }

    // Result is sufficient – return it directly.
    console.log(
      `[researchAgent] Result is sufficient at depth=${depth}. Returning.`
    );
    return { result: searchResult, depth };
  },
});
